#!/usr/bin/env node
/**
 * report-test-failures.js
 *
 * Reads Jest JSON output (test-results.json) and creates GitHub Issues for
 * each failed test that doesn't already have an open issue.
 *
 * Usage:
 *   GITHUB_TOKEN=xxx node scripts/report-test-failures.js
 *
 * Requires: test-results.json in project root (generated by `jest --json --outputFile=test-results.json`)
 */

"use strict";

const fs = require("fs");
const path = require("path");
const https = require("https");

const OWNER = "amitre";
const REPO  = "Mashkanta2";
const TOKEN = process.env.GITHUB_TOKEN;

if (!TOKEN) {
  console.error("GITHUB_TOKEN not set. Skipping issue reporting.");
  process.exit(0);
}

// Labels and their colors to ensure exist
const LABEL_DEFS = [
  { name: "bug",         color: "d73a4a", description: "Something isn't working" },
  { name: "cr",          color: "0075ca", description: "Change Request / New Feature" },
  { name: "P1-critical", color: "b60205", description: "Breaks core functionality" },
  { name: "P2-high",     color: "e4e669", description: "Important, fix soon" },
  { name: "P3-medium",   color: "fbca04", description: "Normal priority" },
  { name: "P4-low",      color: "c2e0c6", description: "Nice to have" },
  { name: "approved",    color: "0e8a16", description: "CR approved for development" },
  { name: "in-progress", color: "1d76db", description: "Currently being developed" },
  { name: "done",        color: "e4e669", description: "Completed" },
];

// Priority by test file
function priorityForFile(testFile) {
  const base = path.basename(testFile || "");
  if (base.includes("calculations")) return "P1-critical";
  if (base.includes("rates-cache"))  return "P2-high";
  if (base.includes("rates-api"))    return "P2-high";
  return "P3-medium";
}

function githubRequest(method, urlPath, body = null) {
  return new Promise((resolve, reject) => {
    const options = {
      hostname: "api.github.com",
      path: urlPath,
      method,
      headers: {
        "Authorization": `token ${TOKEN}`,
        "User-Agent": "mashkanta2-test-reporter",
        "Accept": "application/vnd.github+json",
        "Content-Type": "application/json",
      },
    };

    const req = https.request(options, (res) => {
      let data = "";
      res.on("data", (chunk) => { data += chunk; });
      res.on("end", () => {
        try {
          resolve({ status: res.statusCode, body: JSON.parse(data) });
        } catch {
          resolve({ status: res.statusCode, body: data });
        }
      });
    });

    req.on("error", reject);
    if (body) req.write(JSON.stringify(body));
    req.end();
  });
}

async function ensureLabel(label) {
  const get = await githubRequest("GET", `/repos/${OWNER}/${REPO}/labels/${encodeURIComponent(label.name)}`);
  if (get.status === 200) return; // already exists
  await githubRequest("POST", `/repos/${OWNER}/${REPO}/labels`, {
    name:        label.name,
    color:       label.color,
    description: label.description,
  });
  console.log(`Created label: ${label.name}`);
}

async function findOpenIssue(title) {
  const encoded = encodeURIComponent(`"${title}" repo:${OWNER}/${REPO} is:issue is:open`);
  const res = await githubRequest("GET", `/search/issues?q=${encoded}&per_page=5`);
  if (res.status !== 200) return null;
  return (res.body.items || []).find((i) => i.title === title) || null;
}

async function createIssue(title, body, labels) {
  const res = await githubRequest("POST", `/repos/${OWNER}/${REPO}/issues`, { title, body, labels });
  if (res.status === 201) {
    console.log(`Created issue #${res.body.number}: ${title}`);
  } else {
    console.error(`Failed to create issue: ${JSON.stringify(res.body)}`);
  }
}

async function main() {
  const resultsFile = path.join(process.cwd(), "test-results.json");

  if (!fs.existsSync(resultsFile)) {
    console.log("test-results.json not found — skipping issue reporting");
    process.exit(0);
  }

  const results = JSON.parse(fs.readFileSync(resultsFile, "utf8"));

  // Collect all failures
  const failures = [];
  for (const suite of (results.testResults || [])) {
    for (const test of (suite.testResults || [])) {
      if (test.status === "failed") {
        failures.push({ suite, test });
      }
    }
  }

  if (failures.length === 0) {
    console.log("All tests passed — no issues to report");
    process.exit(0);
  }

  console.log(`Found ${failures.length} test failure(s). Ensuring labels exist...`);

  // Ensure all labels exist
  for (const label of LABEL_DEFS) {
    await ensureLabel(label);
  }

  // Report each failure
  for (const { suite, test } of failures) {
    const priority = priorityForFile(suite.testFilePath);
    const title = `[Bug] ${test.fullName}`;
    const failureMsg = (test.failureMessages || []).join("\n\n");
    const fileRef = suite.testFilePath
      ? path.relative(process.cwd(), suite.testFilePath)
      : "unknown file";

    const body = `## כשל בבדיקה אוטומטית

**שם הבדיקה:** \`${test.fullName}\`
**קובץ:** \`${fileRef}\`
**תאריך:** ${new Date().toISOString()}

## פרטי השגיאה

\`\`\`
${failureMsg}
\`\`\`

## מידע נוסף

- **Suite:** \`${suite.testFilePath || ""}\`
- **Duration:** ${test.duration || 0}ms
- **Priority:** ${priority}

---
*נוצר אוטומטית על ידי GitHub Actions*`;

    const existing = await findOpenIssue(title);
    if (existing) {
      console.log(`Issue already open for: ${title} (#${existing.number})`);
    } else {
      await createIssue(title, body, ["bug", priority]);
    }
  }

  console.log("Done.");
}

main().catch((err) => {
  console.error("report-test-failures.js error:", err);
  process.exit(1);
});
